import{Client}from"basic-ftp";import{PassThrough}from"stream";import{basename,dirname}from"path";import createDebug from"debug";import NotFoundError from"./notfound.js";import NotModifiedError from"./notmodified.js";const debug=createDebug("get-uri:ftp");export const ftp=async(o,t={})=>{const{cache:e}=t,r=decodeURIComponent(o.pathname);let n;if(!r)throw new TypeError('No "pathname"!');const a=new Client;try{const s=o.hostname||o.host||"localhost",i=parseInt(o.port||"0",10)||21,d=o.username?decodeURIComponent(o.username):void 0,m=o.password?decodeURIComponent(o.password):void 0;await a.access({host:s,port:i,user:d,password:m,...t});try{n=await a.lastMod(r)}catch(o){if(550===o.code)throw new NotFoundError}if(!n){const o=await a.list(dirname(r)),t=basename(r),e=o.find(o=>o.name===t);e&&(n=e.modifiedAt)}if(!n)throw new NotFoundError;if(function(){if(e?.lastModified&&n)return+e.lastModified===+n;return!1}())throw new NotModifiedError;const c=new PassThrough,f=c;return a.downloadTo(c,r).then(o=>{debug(o.message),a.close()}),f.lastModified=n,f}catch(o){throw a.close(),o}};